import { createClient } from '@supabase/supabase-js';

// Environment variables are expected to be present in the execution context
const supabaseUrl = process.env.SUPABASE_URL || 'https://your-project.supabase.co';
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY || 'your-anon-key';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

export const TABLES = {
  TRANSACTIONS: 'transactions',
  USERS: 'users'
};

/**
 * Deprecated: Project has migrated to Supabase as per latest requirements.
 * This file is kept to prevent import errors but no longer initializes Firestore
 * to resolve the "Service firestore is not available" issue.
 */

export const db = null as any;
export const COLLECTIONS = {
  TRANSACTIONS: 'transactions',
  USERS: 'users'
};

import React, { useState, useMemo, useEffect } from 'react';
import Navbar from './components/Navbar';
import StatCard from './components/StatCard';
import TransactionForm from './components/TransactionForm';
import ConfirmModal from './components/ConfirmModal';
import ExportModal from './components/ExportModal';
import LoginPage from './components/LoginPage';
import AdminPage from './components/AdminPage';
import TransactionFilters, { FilterState } from './components/TransactionFilters';
import { Transaction, TransactionType, DashboardStats, User, UserRole } from './types';
import { MOCK_TRANSACTIONS, SQL_SNIPPET, PARTICULARS, INITIAL_USERS, CURRENCY, NAMES, LOGO_SVG } from './constants';
import { supabase, TABLES } from './services/supabaseClient';
import { History, Download, SearchX, Plus, ChevronRight, Inbox, Smartphone, X, AlertCircle, ExternalLink, RefreshCw } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [allUsers, setAllUsers] = useState<User[]>(INITIAL_USERS);
  const [view, setView] = useState<'dashboard' | 'statement' | 'sql' | 'admin'>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDbConnected, setIsDbConnected] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [isExportModalOpen, setIsExportModalOpen] = useState(false);
  const [showAddForm, setShowAddForm] = useState(false);

  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [showInstallBanner, setShowInstallBanner] = useState(false);

  const [availableNames, setAvailableNames] = useState<string[]>(NAMES);
  const [availableParticulars, setAvailableParticulars] = useState<string[]>(PARTICULARS);

  const [filters, setFilters] = useState<FilterState>({
    startDate: '',
    endDate: '',
    category: 'All',
    type: 'All',
    name: 'All'
  });

  // Data Fetching and Real-time Sync
  const fetchTransactions = async () => {
    setIsLoading(true);
    try {
      const { data, error: fetchError } = await supabase
        .from(TABLES.TRANSACTIONS)
        .select('*')
        .order('date', { ascending: false });

      if (fetchError) throw fetchError;

      setTransactions(data || []);
      setIsDbConnected(true);
      setError(null);

      // Update suggestion lists
      const uniqueNames = Array.from(new Set((data || []).map((t: any) => t.name))).sort() as string[];
      const uniqueParts = Array.from(new Set((data || []).map((t: any) => t.particular))).sort() as string[];
      setAvailableNames(uniqueNames.length ? uniqueNames : NAMES);
      setAvailableParticulars(uniqueParts.length ? uniqueParts : PARTICULARS);
    } catch (err: any) {
      console.error("Supabase fetch error:", err);
      setIsDbConnected(false);
      setError("Failed to connect to Supabase. Using local/mock data.");
      setTransactions(MOCK_TRANSACTIONS);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (!currentUser) return;
    fetchTransactions();

    // Subscribe to changes
    const channel = supabase
      .channel('schema-db-changes')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: TABLES.TRANSACTIONS },
        () => {
          fetchTransactions();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [currentUser]);

  useEffect(() => {
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
      setShowInstallBanner(true);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, []);

  const handleInstallClick = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    setDeferredPrompt(null);
    setShowInstallBanner(false);
  };

  const handleLogin = async (username: string, password: string): Promise<boolean> => {
    try {
      const { data, error } = await supabase
        .from(TABLES.USERS)
        .select('*')
        .eq('username', username)
        .single();

      if (data && data.password === password) {
        setCurrentUser(data as User);
        return true;
      }

      // Local fallback for dev/demo
      const localUser = allUsers.find(u => u.username === username && u.password === password);
      if (localUser) {
        setCurrentUser(localUser);
        return true;
      }
      return false;
    } catch (err) {
      const localUser = allUsers.find(u => u.username === username && u.password === password);
      if (localUser) {
        setCurrentUser(localUser);
        return true;
      }
      return false;
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setView('dashboard');
  };

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const matchesType = filters.type === 'All' || t.type === filters.type;
      const matchesCategory = filters.category === 'All' || t.particular === filters.category;
      const matchesName = filters.name === 'All' || t.name === filters.name;
      const matchesStart = !filters.startDate || new Date(t.date) >= new Date(filters.startDate);
      const matchesEnd = !filters.endDate || new Date(t.date) <= new Date(filters.endDate);
      return matchesType && matchesCategory && matchesName && matchesStart && matchesEnd;
    });
  }, [transactions, filters]);

  const stats: DashboardStats = useMemo(() => {
    const totalIn = transactions
      .filter(t => t.type === TransactionType.INCOME)
      .reduce((sum, t) => sum + t.amount, 0);
    const totalOut = transactions
      .filter(t => t.type === TransactionType.EXPENSE)
      .reduce((sum, t) => sum + t.amount, 0);

    const monthlyMap: Record<string, { income: number, expense: number }> = {};
    transactions.forEach(t => {
      const monthYear = t.date.substring(0, 7);
      if (!monthlyMap[monthYear]) monthlyMap[monthYear] = { income: 0, expense: 0 };
      if (t.type === TransactionType.INCOME) monthlyMap[monthYear].income += t.amount;
      else monthlyMap[monthYear].expense += t.amount;
    });

    const monthlyData = Object.entries(monthlyMap)
      .map(([month, data]) => ({ month, ...data }))
      .sort((a, b) => a.month.localeCompare(b.month));

    return { totalIn, totalOut, balance: totalIn - totalOut, monthlyData };
  }, [transactions]);

  const handleAddTransaction = async (newT: Omit<Transaction, 'id'>) => {
    if (!isDbConnected) {
      const localT = { ...newT, id: Math.random().toString(36).substr(2, 9) } as Transaction;
      setTransactions([localT, ...transactions]);
      setShowAddForm(false);
      return;
    }
    try {
      const { error } = await supabase.from(TABLES.TRANSACTIONS).insert([newT]);
      if (error) throw error;
      setShowAddForm(false);
    } catch (err) {
      console.error("Supabase Add error:", err);
    }
  };

  const handleUpdateTransaction = async (updatedT: Transaction) => {
    if (!isDbConnected) {
      setTransactions(transactions.map(t => t.id === updatedT.id ? updatedT : t));
      setEditingTransaction(null);
      setShowAddForm(false);
      return;
    }
    try {
      const { id, ...data } = updatedT;
      const { error } = await supabase.from(TABLES.TRANSACTIONS).update(data).eq('id', id);
      if (error) throw error;
      setEditingTransaction(null);
      setShowAddForm(false);
    } catch (err) {
      console.error("Supabase Update error:", err);
    }
  };

  const handleDeleteTransaction = async (id: string) => {
    if (!isDbConnected) {
      setTransactions(transactions.filter(t => t.id !== id));
      setDeleteConfirmId(null);
      setShowAddForm(false);
      return;
    }
    try {
      const { error } = await supabase.from(TABLES.TRANSACTIONS).delete().eq('id', id);
      if (error) throw error;
      setDeleteConfirmId(null);
      setShowAddForm(false);
    } catch (err) {
      console.error("Supabase Delete error:", err);
    }
  };

  const handleEditRequest = (transaction: Transaction) => {
    setEditingTransaction(transaction);
    setShowAddForm(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const resetFilters = () => {
    setFilters({ startDate: '', endDate: '', category: 'All', type: 'All', name: 'All' });
  };

  if (!currentUser) {
    return <LoginPage onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] pb-32 md:pb-10 md:pl-20">
      <Navbar onNavChange={setView} activeView={view} currentUser={currentUser} onLogout={handleLogout} />

      <div className="fixed top-20 right-4 z-[55] hidden md:flex items-center gap-2 px-3 py-1.5 bg-white/80 backdrop-blur border border-slate-100 rounded-full shadow-sm">
        {isDbConnected ? (
          <>
            <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse" />
            <span className="text-[9px] font-black uppercase text-slate-500 tracking-widest">Supabase Live</span>
          </>
        ) : (
          <>
            <div className="w-1.5 h-1.5 bg-amber-500 rounded-full" />
            <span className="text-[9px] font-black uppercase text-slate-500 tracking-widest">Local Cache</span>
          </>
        )}
      </div>

      <main className="max-w-6xl mx-auto px-4 pt-24">
        {view === 'dashboard' && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">

            {error && (
              <div className="bg-amber-50 border border-amber-200 rounded-[2rem] p-6 shadow-sm flex items-start gap-4">
                <div className="bg-amber-100 p-3 rounded-2xl text-amber-600">
                  <AlertCircle size={24} />
                </div>
                <div className="flex-1">
                  <h3 className="text-amber-900 font-bold text-sm">Supabase Sync Issue</h3>
                  <p className="text-amber-700 text-xs mt-1 leading-relaxed">{error}</p>
                </div>
              </div>
            )}

            <header className="flex flex-col md:flex-row md:items-end justify-between gap-4">
              <div>
                <p className="text-[#E31E24] font-bold text-xs uppercase tracking-[0.2em] mb-1">Overview</p>
                <h1 className="text-4xl font-black text-slate-900 tracking-tight">Financial Dashboard</h1>
              </div>
              <button 
                onClick={fetchTransactions}
                className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold text-slate-600 hover:bg-slate-50 transition-all self-start md:self-auto"
              >
                <RefreshCw size={14} className={isLoading ? 'animate-spin' : ''} />
                Refresh Data
              </button>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatCard title="Total Cash In" amount={stats.totalIn} type="income" />
              <StatCard title="Total Cash Out" amount={stats.totalOut} type="expense" />
              <StatCard title="Net Liquidity" amount={stats.balance} type="total" />
            </div>

            <div className="flex items-center justify-between mt-12">
              <h2 className="text-2xl font-black text-slate-900 tracking-tight flex items-center gap-2">
                <History size={24} className="text-[#E31E24]" />
                Recent Activity
              </h2>
              {transactions.length > 0 && (
                <button onClick={() => setView('statement')} className="text-slate-500 font-bold text-xs hover:text-[#E31E24] transition-colors flex items-center gap-1">
                  Full Ledger <ChevronRight size={14} />
                </button>
              )}
            </div>

            <div className="grid grid-cols-1 gap-4">
              {isLoading ? (
                Array.from({ length: 3 }).map((_, i) => <div key={i} className="h-24 bg-white rounded-[2rem] border border-slate-100 shimmer" />)
              ) : transactions.length > 0 ? (
                transactions.slice(0, 6).map((t) => (
                  <div key={t.id} onClick={() => handleEditRequest(t)} className="bg-white p-6 rounded-[2rem] border border-slate-100 flex items-center justify-between hover:shadow-xl hover:shadow-slate-200/50 transition-all cursor-pointer group active:scale-[0.99]">
                    <div className="flex items-center gap-5">
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-bold text-xl ${t.type === TransactionType.INCOME ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {t.type === TransactionType.INCOME ? '+' : '-'}
                      </div>
                      <div>
                        <p className="text-base font-black text-slate-900 group-hover:text-[#E31E24] transition-colors">{t.name}</p>
                        <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">{t.particular} • {t.date}</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className={`font-black text-xl ${t.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-slate-900'}`}>
                        {CURRENCY}{t.amount.toLocaleString('en-IN')}
                      </p>
                    </div>
                  </div>
                ))
              ) : (
                <div className="bg-white rounded-[3rem] p-16 text-center border border-dashed border-slate-200">
                  <div className="inline-flex items-center justify-center p-6 bg-slate-50 rounded-full text-slate-200 mb-6"><Inbox size={48} /></div>
                  <h3 className="text-slate-900 font-black text-lg">No Transactions Yet</h3>
                  <p className="text-slate-400 font-bold text-sm max-w-xs mx-auto mt-2">Start tracking your business finances by adding your first entry below.</p>
                </div>
              )}
            </div>
          </div>
        )}

        {view === 'statement' && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <header className="flex items-end justify-between">
              <div>
                <p className="text-[#E31E24] font-bold text-xs uppercase tracking-[0.2em] mb-1">Reports</p>
                <h1 className="text-4xl font-black text-slate-900 tracking-tight">Ledger Statements</h1>
              </div>
              <button onClick={() => setIsExportModalOpen(true)} disabled={transactions.length === 0} className="p-4 bg-white border border-slate-200 rounded-2xl text-slate-900 hover:bg-slate-50 transition-all shadow-sm disabled:opacity-30">
                <Download size={24} />
              </button>
            </header>

            <TransactionFilters filters={filters} onFilterChange={setFilters} onReset={resetFilters} names={availableNames} particulars={availableParticulars} />

            <div className="space-y-4 pb-20">
              {isLoading ? (
                Array.from({ length: 6 }).map((_, i) => <div key={i} className="h-28 bg-white rounded-[2rem] border border-slate-100 shimmer" />)
              ) : filteredTransactions.length > 0 ? (
                filteredTransactions.map((t) => (
                  <div key={t.id} onClick={() => handleEditRequest(t)} className="bg-white p-6 rounded-[2rem] border border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between hover:shadow-xl hover:shadow-slate-200/50 transition-all cursor-pointer group active:scale-[0.99]">
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-bold text-sm ${t.type === TransactionType.INCOME ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {t.particular.charAt(0) || 'T'}
                      </div>
                      <div>
                        <p className="text-base font-black text-slate-900 group-hover:text-[#E31E24] transition-colors">{t.name}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{t.particular} • {t.date}</p>
                      </div>
                    </div>
                    <div className="text-right mt-4 sm:mt-0">
                      <p className={`font-black text-2xl ${t.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-slate-900'}`}>
                        {t.type === TransactionType.INCOME ? '+' : '-'}{CURRENCY}{t.amount.toLocaleString('en-IN')}
                      </p>
                    </div>
                  </div>
                ))
              ) : (
                <div className="py-24 text-center">
                  <SearchX size={64} className="mx-auto text-slate-200 mb-6" />
                  <h3 className="text-xl font-black text-slate-900">No matching records</h3>
                  <p className="text-slate-400 font-bold text-sm mt-2">Try adjusting your filters to find what you're looking for.</p>
                </div>
              )}
            </div>
          </div>
        )}

        {view === 'admin' && currentUser.role === UserRole.ADMIN && (
          <AdminPage users={allUsers} onAddUser={(u) => setAllUsers([...allUsers, {...u, id: Math.random().toString()}])} onRemoveUser={(id) => setAllUsers(allUsers.filter(user => user.id !== id))} />
        )}

        {view === 'sql' && currentUser.role === UserRole.ADMIN && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
             <header className="flex flex-col gap-1"><p className="text-[#E31E24] font-bold text-xs uppercase tracking-[0.2em]">Developer Console</p><h1 className="text-3xl font-black text-slate-900 tracking-tight">Supabase Insights</h1></header>
             <div className="bg-slate-900 rounded-[2.5rem] p-8 shadow-2xl overflow-hidden font-mono text-xs leading-relaxed">
               <pre className="text-emerald-400 whitespace-pre-wrap">{SQL_SNIPPET}</pre>
             </div>
          </div>
        )}
      </main>

      {showAddForm && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center animate-in fade-in duration-300">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => { setShowAddForm(false); setEditingTransaction(null); }} />
          <div className="relative w-full max-w-2xl bg-white rounded-t-[3rem] sm:rounded-[3rem] shadow-2xl p-8 sm:p-12 animate-in slide-in-from-bottom-12 duration-500 overflow-y-auto max-h-[95vh] no-scrollbar">
            <TransactionForm onAdd={handleAddTransaction} onUpdate={handleUpdateTransaction} onDelete={(id) => setDeleteConfirmId(id)} editingTransaction={editingTransaction} onCancelEdit={() => { setShowAddForm(false); setEditingTransaction(null); }} availableNames={availableNames} availableParticulars={availableParticulars} />
          </div>
        </div>
      )}

      <button 
        onClick={() => setShowAddForm(true)} 
        className="fixed bottom-24 right-6 md:right-10 md:bottom-10 z-[70] w-16 h-16 bg-[#E31E24] text-white rounded-[2rem] shadow-2xl shadow-red-200 flex items-center justify-center transition-all hover:scale-110 active:scale-95 animate-in zoom-in duration-300"
      >
        <Plus size={32} />
      </button>

      <ConfirmModal isOpen={!!deleteConfirmId} onClose={() => setDeleteConfirmId(null)} onConfirm={() => handleDeleteTransaction(deleteConfirmId!)} title="Delete record?" message="This transaction will be permanently removed from the ledger." />
      <ExportModal isOpen={isExportModalOpen} onClose={() => setIsExportModalOpen(false)} transactions={transactions} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Transaction, TransactionType } from '../types';
import { CURRENCY } from '../constants';
import { 
  Sparkles, Loader2, Save, Trash2, Calendar, User, Tag, 
  MessageSquare, Wand2, X, ChevronDown, Check, Search,
  ShoppingCart, Briefcase, Utensils, Zap, Car, Home, Plus
} from 'lucide-react';
import { suggestCategory } from '../services/geminiService';

interface TransactionFormProps {
  onAdd: (t: Omit<Transaction, 'id'>) => void;
  onUpdate: (t: Transaction) => void;
  onDelete: (id: string) => void;
  editingTransaction?: Transaction | null;
  onCancelEdit: () => void;
  availableNames: string[];
  availableParticulars: string[];
}

const PRESET_CATEGORIES = [
  { name: 'Inventory', icon: <ShoppingCart size={14} /> },
  { name: 'Salary', icon: <Briefcase size={14} /> },
  { name: 'Food/Meals', icon: <Utensils size={14} /> },
  { name: 'Electricity', icon: <Zap size={14} /> },
  { name: 'Transport', icon: <Car size={14} /> },
  { name: 'Rent', icon: <Home size={14} /> },
  { name: 'Miscellaneous', icon: <Plus size={14} /> },
];

const QUICK_AMOUNTS = [100, 500, 1000, 5000];

const TransactionForm: React.FC<TransactionFormProps> = ({ 
  onAdd, 
  onUpdate, 
  onDelete, 
  editingTransaction, 
  onCancelEdit,
  availableNames,
  availableParticulars
}) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [name, setName] = useState('');
  const [particular, setParticular] = useState('');
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [type, setType] = useState<TransactionType>(TransactionType.EXPENSE);
  const [isCategorizing, setIsCategorizing] = useState(false);
  const [suggestedCategory, setSuggestedCategory] = useState<string | null>(null);

  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (editingTransaction) {
      setDate(editingTransaction.date);
      setName(editingTransaction.name);
      setParticular(editingTransaction.particular);
      setDescription(editingTransaction.description || '');
      setAmount(editingTransaction.amount.toString());
      setType(editingTransaction.type);
    } else {
      setName('');
      setParticular('');
    }
  }, [editingTransaction]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSuggest = async () => {
    if (!description.trim() || description.length < 3) return;
    setIsCategorizing(true);
    try {
      const suggestion = await suggestCategory(description, [...new Set([...availableParticulars, ...PRESET_CATEGORIES.map(c => c.name)])]);
      setSuggestedCategory(suggestion);
    } catch (err) {
      console.error("AI suggestion failed", err);
    } finally {
      setIsCategorizing(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !particular || !amount) return;

    const transactionData = {
      name,
      particular,
      description,
      amount: parseFloat(amount),
      type,
      category: particular,
      date
    };

    if (editingTransaction) {
      onUpdate({ ...transactionData, id: editingTransaction.id });
    } else {
      onAdd(transactionData);
    }
  };

  const allCategories = Array.from(new Set([...PRESET_CATEGORIES.map(c => c.name), ...availableParticulars]));
  const filteredCategories = allCategories.filter(cat => 
    cat.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <form onSubmit={handleSubmit} className="space-y-8 max-w-lg mx-auto">
      <div className="flex items-center justify-between">
        <h2 className="text-3xl font-black text-slate-900 tracking-tighter">
          {editingTransaction ? 'Edit Entry' : 'New Transaction'}
        </h2>
        <button type="button" onClick={onCancelEdit} className="p-2 text-slate-400 hover:text-slate-600 transition-colors">
          <X size={24} />
        </button>
      </div>

      {/* Type Selector Toggle */}
      <div className="relative p-1.5 bg-slate-100 rounded-[1.5rem] flex items-center">
        <div 
          className={`absolute h-[calc(100%-12px)] w-[calc(50%-6px)] bg-white rounded-[1.1rem] shadow-sm transition-all duration-300 ease-out ${
            type === TransactionType.INCOME ? 'translate-x-full' : 'translate-x-0'
          }`}
        />
        <button
          type="button"
          onClick={() => setType(TransactionType.EXPENSE)}
          className={`relative z-10 flex-1 py-3 text-xs font-black uppercase tracking-widest transition-colors ${
            type === TransactionType.EXPENSE ? 'text-rose-600' : 'text-slate-400'
          }`}
