                type="date"
                className="w-full pl-11 pr-4 py-4 bg-slate-50 border-none rounded-2xl focus:ring-2 focus:ring-[#E31E24] text-sm font-bold text-slate-900 transition-all"
                value={date}
                onChange={(e) => setDate(e.target.value)}
