            {!isSupabaseConfigured && showErrorBanner && (
              <div className="bg-blue-50 border border-blue-200 rounded-[2rem] p-6 shadow-sm flex items-start gap-4 animate-in slide-in-from-top-2">
                <div className="bg-blue-100 p-3 rounded-2xl text-blue-600">
                  <Info size={24} />
