                <div className="flex-1">
                  <h3 className="text-blue-900 font-bold text-sm">Developer Notice: Local Storage Mode</h3>
                  <p className="text-blue-700 text-xs mt-1 leading-relaxed">Setup SUPABASE_URL and SUPABASE_ANON_KEY to enable cloud persistence. Current changes are saved locally.</p>
                </div>
                <button onClick={() => setShowErrorBanner(false)} className="p-2 hover:bg-blue-100 rounded-xl transition-colors">
                  <X size={16} className="text-blue-400" />
