        {view === 'sql' && currentUser.role === UserRole.ADMIN && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
             <header className="flex flex-col gap-1"><p className="text-[#E31E24] font-bold text-xs uppercase tracking-[0.2em]">Developer Console</p><h1 className="text-3xl font-black text-slate-900 tracking-tight">Database Insights</h1></header>
             <div className="bg-slate-900 rounded-[2.5rem] p-8 shadow-2xl overflow-hidden font-mono text-xs leading-relaxed border-4 border-slate-800">
               <pre className="text-emerald-400 whitespace-pre-wrap">{SQL_SNIPPET}</pre>
