                      <div>
                        <p className="text-base font-black text-slate-900 group-hover:text-[#E31E24] transition-colors">{t.name}</p>
                        <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">{t.particular} • {t.date}</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className={`font-black text-xl ${t.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-slate-900'}`}>
                        {CURRENCY}{t.amount.toLocaleString('en-IN')}
                      </p>
                    </div>
                  </div>
                ))
              ) : (
                <div className="bg-white rounded-[3rem] p-16 text-center border border-dashed border-slate-200">
                  <div className="inline-flex items-center justify-center p-6 bg-slate-50 rounded-full text-slate-200 mb-6"><Inbox size={48} /></div>
                  <h3 className="text-slate-900 font-black text-lg">Empty Ledger</h3>
                  <p className="text-slate-400 font-bold text-sm max-w-xs mx-auto mt-2">Start tracking SR INFOTECH finances by adding your first entry.</p>
                </div>
              )}
            </div>
          </div>
        )}

        {view === 'statement' && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <header className="flex items-end justify-between">
              <div>
                <p className="text-[#E31E24] font-bold text-xs uppercase tracking-[0.2em] mb-1">Accounting</p>
                <h1 className="text-4xl font-black text-slate-900 tracking-tight">Statement Ledger</h1>
              </div>
              <button onClick={() => setIsExportModalOpen(true)} disabled={transactions.length === 0} className="p-4 bg-white border border-slate-200 rounded-2xl text-slate-900 hover:bg-slate-50 transition-all shadow-sm disabled:opacity-30">
                <Download size={24} />
              </button>
            </header>

            <TransactionFilters filters={filters} onFilterChange={setFilters} onReset={resetFilters} names={availableNames} particulars={availableParticulars} />

            <div className="space-y-4 pb-20">
              {isLoading && transactions.length === 0 ? (
                Array.from({ length: 6 }).map((_, i) => <div key={i} className="h-28 bg-white rounded-[2rem] border border-slate-100 shimmer" />)
              ) : filteredTransactions.length > 0 ? (
                filteredTransactions.map((t) => (
                  <div key={t.id} onClick={() => handleEditRequest(t)} className="bg-white p-6 rounded-[2rem] border border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between hover:shadow-xl hover:shadow-slate-200/50 transition-all cursor-pointer group active:scale-[0.99]">
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-bold text-sm ${t.type === TransactionType.INCOME ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                        {t.particular.charAt(0) || 'T'}
                      </div>
                      <div>
                        <p className="text-base font-black text-slate-900 group-hover:text-[#E31E24] transition-colors">{t.name}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{t.particular} • {t.date}</p>
                      </div>
                    </div>
                    <div className="text-right mt-4 sm:mt-0">
                      <p className={`font-black text-2xl ${t.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-slate-900'}`}>
                        {t.type === TransactionType.INCOME ? '+' : '-'}{CURRENCY}{t.amount.toLocaleString('en-IN')}
                      </p>
                    </div>
                  </div>
                ))
              ) : (
                <div className="py-24 text-center">
                  <SearchX size={64} className="mx-auto text-slate-200 mb-6" />
                  <h3 className="text-xl font-black text-slate-900">No results found</h3>
                  <p className="text-slate-400 font-bold text-sm mt-2">Adjust your search or filters to locate specific entries.</p>
                </div>
              )}
            </div>
          </div>
        )}

        {view === 'reports' && (
          <ReportPage transactions={transactions} />
        )}

        {view === 'admin' && (
          <AdminPage 
            users={allUsers} 
            onAddUser={(u) => setAllUsers([...allUsers, { ...u, id: Math.random().toString(36).substr(2, 9) }])} 
            onRemoveUser={(id) => setAllUsers(allUsers.filter(u => u.id !== id))} 
          />
        )}

        {view === 'sql' && (
          <div className="bg-slate-900 rounded-[2.5rem] p-8 text-white space-y-6">
            <div className="flex items-center gap-3 mb-6">
              <Database className="text-[#E31E24]" size={32} />
              <h1 className="text-3xl font-black">Developer Console</h1>
            </div>
            <div className="bg-slate-800 p-6 rounded-2xl border border-slate-700">
              <h3 className="font-bold text-slate-300 mb-2 flex items-center gap-2">
                <Info size={16} /> Database Setup Script
              </h3>
              <p className="text-xs text-slate-400 mb-4">Run this in your Supabase SQL Editor to ensure the schema is up to date.</p>
              <pre className="bg-black/50 p-6 rounded-2xl overflow-x-auto text-xs font-mono text-emerald-400 no-scrollbar">
                {SQL_SNIPPET}
              </pre>
            </div>
          </div>
        )}
      </main>

      {/* Modals & Overlays */}
      {showAddForm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => { setShowAddForm(false); setEditingTransaction(null); }} />
          <div className="relative bg-white w-full max-w-xl rounded-[3rem] p-8 shadow-2xl overflow-y-auto max-h-[90vh] no-scrollbar">
            <TransactionForm 
              onAdd={handleAddTransaction} 
              onUpdate={handleUpdateTransaction} 
              onDelete={(id) => setDeleteConfirmId(id)}
              editingTransaction={editingTransaction}
              onCancelEdit={() => { setShowAddForm(false); setEditingTransaction(null); }}
              availableNames={availableNames}
              availableParticulars={availableParticulars}
            />
          </div>
        </div>
      )}

      <ConfirmModal 
        isOpen={!!deleteConfirmId} 
        onClose={() => setDeleteConfirmId(null)} 
        onConfirm={() => deleteConfirmId && handleDeleteTransaction(deleteConfirmId)} 
        title="Delete Transaction?" 
        message="This action cannot be undone. The entry will be permanently removed from the ledger." 
      />

      <ExportModal 
        isOpen={isExportModalOpen} 
        onClose={() => setIsExportModalOpen(false)} 
        transactions={filteredTransactions} 
        driveAccount={driveAccount} 
      />

      {showCloudModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setShowCloudModal(false)} />
          <div className="relative bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
                <CloudOff className="text-[#E31E24]" size={24} />
                <h2 className="text-2xl font-black text-slate-900">Cloud Sync</h2>
              </div>
              <button onClick={() => setShowCloudModal(false)} className="text-slate-400 hover:text-slate-600"><X /></button>
            </div>
            <form onSubmit={handleCloudSetup} className="space-y-4">
              <div>
                <label className="block text-[10px] font-black uppercase text-slate-400 mb-2">Supabase Project URL</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-[#E31E24] font-mono text-xs"
                  value={cloudUrl}
                  onChange={e => setCloudUrl(e.target.value)}
                  placeholder="https://your-project.supabase.co"
                />
              </div>
              <div>
                <label className="block text-[10px] font-black uppercase text-slate-400 mb-2">Anon API Key</label>
                <input 
                  type="password" 
                  className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-[#E31E24] font-mono text-xs"
                  value={cloudKey}
                  onChange={e => setCloudKey(e.target.value)}
                  placeholder="eyJhbG..."
                />
              </div>
              <div>
                <label className="block text-[10px] font-black uppercase text-slate-400 mb-2">Organization Email</label>
                <input 
                  type="email" 
                  className="w-full px-4 py-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-[#E31E24] font-bold text-xs"
                  value={driveAccount}
                  onChange={e => setDriveAccount(e.target.value)}
                />
              </div>
              <button type="submit" className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest text-xs mt-4">Save Configuration</button>
            </form>
          </div>
        </div>
      )}

      {/* Floating Add Button */}
      {!showAddForm && (
        <button 
          onClick={() => { setEditingTransaction(null); setShowAddForm(true); }}
          className="fixed bottom-24 right-6 md:bottom-10 md:right-10 z-[55] w-16 h-16 bg-[#E31E24] text-white rounded-full shadow-2xl shadow-red-200 flex items-center justify-center hover:scale-110 active:scale-95 transition-all group"
        >
          <Plus size={32} className="group-hover:rotate-90 transition-transform" />
        </button>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Transaction, TransactionType } from '../types';
import { CURRENCY, LOGO_URL } from '../constants';
import { 
  FileText, Calendar, Download, ChevronDown, PieChart, 
  ArrowUpRight, ArrowDownRight, Wallet, Printer, 
  FileCheck, Clock
} from 'lucide-react';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

interface ReportPageProps {
  transactions: Transaction[];
}

type ReportType = 'monthly' | 'quarterly' | 'annual';

const ReportPage: React.FC<ReportPageProps> = ({ transactions }) => {
  const [reportType, setReportType] = useState<ReportType>('monthly');
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedQuarter, setSelectedQuarter] = useState(Math.floor(new Date().getMonth() / 3) + 1);

  const years = useMemo(() => {
    const yearsSet = new Set(transactions.map(t => new Date(t.date).getFullYear()));
    yearsSet.add(new Date().getFullYear());
    return Array.from(yearsSet).sort((a, b) => b - a);
  }, [transactions]);

  const filteredData = useMemo(() => {
    return transactions.filter(t => {
      const date = new Date(t.date);
      const yearMatches = date.getFullYear() === selectedYear;

      if (!yearMatches) return false;

      if (reportType === 'monthly') {
        return date.getMonth() === selectedMonth;
      } else if (reportType === 'quarterly') {
        const q = Math.floor(date.getMonth() / 3) + 1;
        return q === selectedQuarter;
      } else {
        return true; // Annual just matches year
      }
    }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, reportType, selectedYear, selectedMonth, selectedQuarter]);

  const stats = useMemo(() => {
    const income = filteredData.filter(t => t.type === TransactionType.INCOME).reduce((s, t) => s + t.amount, 0);
    const expense = filteredData.filter(t => t.type === TransactionType.EXPENSE).reduce((s, t) => s + t.amount, 0);
    return { income, expense, balance: income - expense };
  }, [filteredData]);

  const generatePDF = () => {
    const doc = new jsPDF();
    const period = reportType === 'monthly' 
      ? `${new Intl.DateTimeFormat('en-US', { month: 'long' }).format(new Date(selectedYear, selectedMonth))} ${selectedYear}`
      : reportType === 'quarterly' 
      ? `Q${selectedQuarter} ${selectedYear}`
      : `Annual Report ${selectedYear}`;

    // Header Branding
    doc.setFillColor(227, 30, 36); // SR Red
    doc.rect(0, 0, 210, 40, 'F');

    doc.setTextColor(255, 255, 255);
    doc.setFontSize(22);
    doc.setFont('helvetica', 'bold');
    doc.text('SR INFOTECH', 15, 25);

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text('FINANCIAL INTELLIGENCE PORTAL', 15, 32);

    doc.setFontSize(14);
    doc.text(period.toUpperCase(), 195, 25, { align: 'right' });

    // Summary Section
    doc.setTextColor(15, 23, 42); // Slate 900
    doc.setFontSize(16);
    doc.setFont('helvetica', 'bold');
    doc.text('Summary Overview', 15, 55);

    doc.setDrawColor(241, 245, 249);
    doc.line(15, 58, 195, 58);

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(100, 116, 139); // Slate 500
    doc.text('Total Cash In:', 15, 70);
    doc.text('Total Cash Out:', 80, 70);
    doc.text('Net Balance:', 145, 70);

    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(16, 185, 129); // Emerald 500
    doc.text(`${CURRENCY}${stats.income.toLocaleString()}`, 15, 80);

    doc.setTextColor(227, 30, 36); // SR Red
    doc.text(`${CURRENCY}${stats.expense.toLocaleString()}`, 80, 80);

    doc.setTextColor(15, 23, 42); // Slate 900
    doc.text(`${CURRENCY}${stats.balance.toLocaleString()}`, 145, 80);

    // Table
    const tableData = filteredData.map(t => [
      t.date,
      t.name,
      t.particular,
      t.type.toUpperCase(),
      `${CURRENCY}${t.amount.toLocaleString()}`
    ]);

    autoTable(doc, {
      startY: 95,
      head: [['Date', 'Entity', 'Category', 'Type', 'Amount']],
      body: tableData,
      theme: 'striped',
      headStyles: { fillColor: [227, 30, 36], textColor: [255, 255, 255], fontStyle: 'bold' },
      styles: { fontSize: 9, cellPadding: 4 },
      columnStyles: {
        4: { halign: 'right', fontStyle: 'bold' }
      }
    });

    // Footer
    const pageCount = doc.internal.getNumberOfPages();
    for(let i = 1; i <= pageCount; i++) {
      doc.setPage(i);
      doc.setFontSize(8);
      doc.setTextColor(148, 163, 184);
      doc.text(`Generated on ${new Date().toLocaleString()} | Page ${i} of ${pageCount}`, 105, 285, { align: 'center' });
    }

    doc.save(`SR_Report_${period.replace(/ /g, '_')}.pdf`);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <p className="text-[#E31E24] font-bold text-xs uppercase tracking-[0.2em] mb-1">Financial Analysis</p>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Financial Reports</h1>
        </div>

        <div className="flex flex-wrap items-center gap-3">
          <div className="flex p-1 bg-white border border-slate-100 rounded-2xl shadow-sm">
            {(['monthly', 'quarterly', 'annual'] as ReportType[]).map((type) => (
              <button
                key={type}
                onClick={() => setReportType(type)}
                className={`px-4 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${
                  reportType === type ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'
                }`}
              >
                {type}
              </button>
            ))}
          </div>

          <button 
            onClick={generatePDF}
            className="flex items-center gap-2 px-6 py-3 bg-[#E31E24] text-white rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-red-100 hover:bg-red-700 active:scale-95 transition-all"
          >
            <Download size={16} />
            Download PDF
          </button>
        </div>
      </header>

      {/* Selectors Bar */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm">
        <div className="space-y-2">
          <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Reporting Year</label>
          <div className="relative">
            <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
            <select 
              value={selectedYear}
              onChange={(e) => setSelectedYear(parseInt(e.target.value))}
              className="w-full pl-11 pr-10 py-3.5 bg-slate-50 border-none rounded-2xl appearance-none outline-none focus:ring-2 focus:ring-[#E31E24] font-bold text-slate-900 text-sm"
            >
              {years.map(y => <option key={y} value={y}>{y}</option>)}
            </select>
            <ChevronDown size={14} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none" />
          </div>
        </div>

        {reportType === 'monthly' && (
          <div className="space-y-2 animate-in zoom-in-95">
            <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Specific Month</label>
            <div className="relative">
              <Clock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
              <select 
                value={selectedMonth}
                onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
                className="w-full pl-11 pr-10 py-3.5 bg-slate-50 border-none rounded-2xl appearance-none outline-none focus:ring-2 focus:ring-[#E31E24] font-bold text-slate-900 text-sm"
              >
                {Array.from({ length: 12 }).map((_, i) => (
                  <option key={i} value={i}>{new Intl.DateTimeFormat('en-US', { month: 'long' }).format(new Date(2000, i, 1))}</option>
                ))}
              </select>
              <ChevronDown size={14} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none" />
            </div>
          </div>
        )}

        {reportType === 'quarterly' && (
          <div className="space-y-2 animate-in zoom-in-95">
            <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Fiscal Quarter</label>
            <div className="relative">
              <PieChart className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
              <select 
                value={selectedQuarter}
                onChange={(e) => setSelectedQuarter(parseInt(e.target.value))}
                className="w-full pl-11 pr-10 py-3.5 bg-slate-50 border-none rounded-2xl appearance-none outline-none focus:ring-2 focus:ring-[#E31E24] font-bold text-slate-900 text-sm"
              >
                <option value={1}>Q1 (Jan - Mar)</option>
                <option value={2}>Q2 (Apr - Jun)</option>
                <option value={3}>Q3 (Jul - Sep)</option>
                <option value={4}>Q4 (Oct - Dec)</option>
              </select>
              <ChevronDown size={14} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none" />
            </div>
          </div>
        )}
      </div>

      {/* Summary Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-emerald-50 rounded-[2.5rem] p-8 border border-emerald-100 flex items-center gap-6">
          <div className="w-14 h-14 bg-white rounded-2xl flex items-center justify-center text-emerald-600 shadow-sm">
            <ArrowUpRight size={28} />
          </div>
          <div>
            <p className="text-emerald-700/60 font-black text-[10px] uppercase tracking-widest mb-1">Period Cash In</p>
            <h3 className="text-3xl font-black text-emerald-900">{CURRENCY}{stats.income.toLocaleString()}</h3>
          </div>
        </div>

        <div className="bg-rose-50 rounded-[2.5rem] p-8 border border-rose-100 flex items-center gap-6">
          <div className="w-14 h-14 bg-white rounded-2xl flex items-center justify-center text-rose-600 shadow-sm">
            <ArrowDownRight size={28} />
          </div>
          <div>
            <p className="text-rose-700/60 font-black text-[10px] uppercase tracking-widest mb-1">Period Cash Out</p>
            <h3 className="text-3xl font-black text-rose-900">{CURRENCY}{stats.expense.toLocaleString()}</h3>
          </div>
        </div>

        <div className="bg-slate-900 rounded-[2.5rem] p-8 border border-slate-800 flex items-center gap-6">
          <div className="w-14 h-14 bg-white/10 rounded-2xl flex items-center justify-center text-white shadow-sm">
            <Wallet size={28} />
          </div>
          <div>
            <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest mb-1">Net Flow</p>
            <h3 className="text-3xl font-black text-white">{CURRENCY}{stats.balance.toLocaleString()}</h3>
          </div>
        </div>
      </div>

      {/* Preview Table */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="px-8 py-6 border-b border-slate-50 flex items-center justify-between bg-slate-50/50">
          <div className="flex items-center gap-3">
            <FileCheck className="text-[#E31E24]" size={20} />
