import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Transaction, TransactionType } from '../types';
import { CURRENCY } from '../constants';

interface PDFExportOptions {
  title: string;
  period: string;
  stats: {
    income: number;
    expense: number;
    balance: number;
  };
}

export const generateFinancialPDF = (transactions: Transaction[], options: PDFExportOptions) => {
  const doc = new jsPDF();
  const { title, period, stats } = options;

  // Header Branding
  doc.setFillColor(227, 30, 36); // SR Red
  doc.rect(0, 0, 210, 40, 'F');

  doc.setTextColor(255, 255, 255);
  doc.setFontSize(22);
  doc.setFont('helvetica', 'bold');
  doc.text('SR INFOTECH', 15, 25);

  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text(title.toUpperCase(), 15, 32);

  doc.setFontSize(14);
  doc.text(period.toUpperCase(), 195, 25, { align: 'right' });

  // Summary Section
  doc.setTextColor(15, 23, 42); // Slate 900
  doc.setFontSize(16);
  doc.setFont('helvetica', 'bold');
  doc.text('Summary Overview', 15, 55);

  doc.setDrawColor(241, 245, 249);
  doc.line(15, 58, 195, 58);

  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(100, 116, 139); // Slate 500
  doc.text('Total Cash In:', 15, 70);
  doc.text('Total Cash Out:', 80, 70);
  doc.text('Net Balance:', 145, 70);

  doc.setFontSize(14);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(16, 185, 129); // Emerald 500
  doc.text(`${CURRENCY}${stats.income.toLocaleString()}`, 15, 80);

  doc.setTextColor(227, 30, 36); // SR Red
  doc.text(`${CURRENCY}${stats.expense.toLocaleString()}`, 80, 80);

  doc.setTextColor(15, 23, 42); // Slate 900
  doc.text(`${CURRENCY}${stats.balance.toLocaleString()}`, 145, 80);

  // Table
  const tableData = transactions.map(t => [
    t.date,
    t.name,
    t.particular,
    t.type.toUpperCase(),
    `${CURRENCY}${t.amount.toLocaleString()}`
  ]);

  autoTable(doc, {
    startY: 95,
    head: [['Date', 'Entity', 'Category', 'Type', 'Amount']],
    body: tableData,
    theme: 'striped',
    headStyles: { fillColor: [227, 30, 36], textColor: [255, 255, 255], fontStyle: 'bold' },
    styles: { fontSize: 9, cellPadding: 4 },
    columnStyles: {
      4: { halign: 'right', fontStyle: 'bold' }
    }
  });

  // Footer
  const pageCount = doc.internal.getNumberOfPages();
  for(let i = 1; i <= pageCount; i++) {
    doc.setPage(i);
    doc.setFontSize(8);
    doc.setTextColor(148, 163, 184);
    doc.text(`Generated on ${new Date().toLocaleString()} | Page ${i} of ${pageCount}`, 105, 285, { align: 'center' });
  }

  doc.save(`SR_Financial_Statement_${period.replace(/ /g, '_')}.pdf`);
};

import React from 'react';
import { TransactionType } from '../types';
import { Filter, Search, X, Calendar as CalendarIcon, ChevronDown } from 'lucide-react';

export interface FilterState {
  period: 'All' | 'Today' | 'This Week' | 'This Month' | 'Custom Range';
  startDate: string;
  endDate: string;
  category: string;
  type: string;
  name: string;
  search: string;
}

interface TransactionFiltersProps {
  filters: FilterState;
  onFilterChange: (filters: FilterState) => void;
  onReset: () => void;
  names: string[];
  particulars: string[];
  hideSearch?: boolean;
}

const TransactionFilters: React.FC<TransactionFiltersProps> = ({ 
  filters, 
  onFilterChange, 
  onReset,
  names,
  particulars,
  hideSearch = false
}) => {
  const hasActiveFilters = 
    filters.period !== 'All' || 
    filters.startDate || 
    filters.endDate || 
    filters.category !== 'All' || 
    filters.type !== 'All' || 
    filters.name !== 'All' ||
    filters.search !== '';

  const handlePeriodChange = (period: FilterState['period']) => {
    const now = new Date();
    let start = '';
    let end = now.toISOString().split('T')[0];

    if (period === 'Today') {
      start = end;
    } else if (period === 'This Week') {
      const day = now.getDay();
      const diff = now.getDate() - day + (day === 0 ? -6 : 1); // Adjust to Monday
      const monday = new Date(now.setDate(diff));
      start = monday.toISOString().split('T')[0];
    } else if (period === 'This Month') {
      const firstDay = new Date(now.getFullYear(), now.getMonth(), 1);
      start = firstDay.toISOString().split('T')[0];
    } else if (period === 'All') {
      start = '';
      end = '';
    }

    onFilterChange({
      ...filters,
      period,
      startDate: period === 'Custom Range' ? filters.startDate : start,
      endDate: period === 'Custom Range' ? filters.endDate : end,
    });
  };

  return (
    <div className="space-y-4 animate-in fade-in duration-500">
      {/* Search Bar */}
      {!hideSearch && (
        <div className="relative group">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-[#E31E24] transition-colors" size={18} />
          <input
            type="text"
            placeholder="Search by name, category or description..."
            className="w-full pl-12 pr-10 py-4 bg-white border border-slate-100 rounded-2xl focus:ring-2 focus:ring-red-100 outline-none transition-all font-bold text-slate-900 text-sm shadow-sm placeholder-slate-300"
            value={filters.search}
            onChange={(e) => onFilterChange({...filters, search: e.target.value})}
          />
          {filters.search && (
            <button 
              onClick={() => onFilterChange({...filters, search: ''})}
              className="absolute right-4 top-1/2 -translate-y-1/2 p-1 hover:bg-slate-100 rounded-full text-slate-400 transition-colors"
            >
              <X size={14} />
            </button>
          )}
        </div>
      )}

      <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-2">
        <button 
          onClick={onReset}
          className={`flex-shrink-0 px-4 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${
            !hasActiveFilters ? 'bg-slate-900 text-white' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
          }`}
        >
          <Filter size={12} />
          Reset
        </button>

        {/* Period Dropdown */}
        <div className="relative flex-shrink-0">
          <select 
            value={filters.period}
            onChange={(e) => handlePeriodChange(e.target.value as any)}
            className={`pl-4 pr-10 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest outline-none border-none appearance-none cursor-pointer transition-all ${
              filters.period !== 'All' ? 'bg-red-50 text-[#E31E24] ring-1 ring-red-100' : 'bg-white text-slate-500 ring-1 ring-slate-100'
            }`}
          >
            <option value="All">All Time</option>
            <option value="Today">Today</option>
            <option value="This Week">This Week</option>
            <option value="This Month">This Month</option>
            <option value="Custom Range">Custom Range</option>
          </select>
          <ChevronDown size={12} className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none opacity-50" />
        </div>

        <div className="relative flex-shrink-0">
          <select 
            value={filters.type}
            onChange={(e) => onFilterChange({...filters, type: e.target.value})}
            className={`pl-4 pr-10 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest outline-none border-none appearance-none cursor-pointer transition-all ${
              filters.type !== 'All' ? 'bg-red-50 text-[#E31E24] ring-1 ring-red-100' : 'bg-white text-slate-500 ring-1 ring-slate-100'
            }`}
          >
            <option value="All">All Types</option>
            <option value={TransactionType.INCOME}>Cash In</option>
            <option value={TransactionType.EXPENSE}>Cash Out</option>
          </select>
          <ChevronDown size={12} className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none opacity-50" />
        </div>

        <div className="relative flex-shrink-0">
          <select 
            value={filters.name}
            onChange={(e) => onFilterChange({...filters, name: e.target.value})}
            className={`pl-4 pr-10 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest outline-none border-none appearance-none cursor-pointer transition-all ${
              filters.name !== 'All' ? 'bg-red-50 text-[#E31E24] ring-1 ring-red-100' : 'bg-white text-slate-500 ring-1 ring-slate-100'
            }`}
          >
            <option value="All">All Entities</option>
            {names.map(n => <option key={n} value={n}>{n}</option>)}
          </select>
          <ChevronDown size={12} className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none opacity-50" />
        </div>

        <div className="relative flex-shrink-0">
          <select 
            value={filters.category}
            onChange={(e) => onFilterChange({...filters, category: e.target.value})}
            className={`pl-4 pr-10 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest outline-none border-none appearance-none cursor-pointer transition-all ${
              filters.category !== 'All' ? 'bg-red-50 text-[#E31E24] ring-1 ring-red-100' : 'bg-white text-slate-500 ring-1 ring-slate-100'
            }`}
          >
            <option value="All">All Categories</option>
            {particulars.map(p => <option key={p} value={p}>{p}</option>)}
          </select>
          <ChevronDown size={12} className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none opacity-50" />
        </div>
      </div>

      {filters.period === 'Custom Range' && (
        <div className="grid grid-cols-2 gap-3 animate-in slide-in-from-top-2 duration-300">
          <div className="relative">
            <CalendarIcon size={12} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
            <input
              type="date"
              className="w-full bg-white pl-10 pr-4 py-3 rounded-2xl text-[10px] font-bold text-slate-500 ring-1 ring-slate-100 border-none outline-none focus:ring-2 focus:ring-red-100 transition-all"
              value={filters.startDate}
              onChange={(e) => onFilterChange({...filters, startDate: e.target.value})}
            />
          </div>
          <div className="relative">
            <CalendarIcon size={12} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
            <input
              type="date"
              className="w-full bg-white pl-10 pr-4 py-3 rounded-2xl text-[10px] font-bold text-slate-500 ring-1 ring-slate-100 border-none outline-none focus:ring-2 focus:ring-red-100 transition-all"
              value={filters.endDate}
              onChange={(e) => onFilterChange({...filters, endDate: e.target.value})}
            />
          </div>
        </div>
      )}
    </div>
  );
};

